components.css:
.ds-btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 10px 24px;
  background: var(--brand-500);
  color: #ffffff;
  font-family: var(--font-body);
  font-size: var(--fs-sm);
  font-weight: 600;
  line-height: 1;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  transition: background-color 0.2s ease, transform 0.16s cubic-bezier(0.16, 1, 0.3, 1);
}
.ds-btn-primary:hover {
  background: var(--brand-600);
}
.ds-btn-primary:active {
  background: var(--brand-700);
  transform: scale(0.98);
}
.ds-btn-primary:focus-visible {
  outline: 2px solid var(--brand-500);
  outline-offset: 2px;
}
.ds-btn-primary:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  pointer-events: none;
}

.ds-btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  height: 36px;
  padding: 10px 16px;
  background: transparent;
  color: var(--text-secondary);
  font-family: var(--font-body);
  font-size: var(--fs-sm);
  font-weight: 500;
  line-height: 1;
  border: 1px solid var(--line-soft);
  border-radius: 12px;
  cursor: pointer;
  transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
}
.ds-btn-ghost:hover {
  background: var(--surface-3);
  color: var(--text-primary);
  border-color: var(--line-strong);
}
.ds-btn-ghost:focus-visible {
  outline: 2px solid var(--brand-500);
  outline-offset: 2px;
}
.ds-icon {
  flex-shrink: 0;
  width: 18px;
  height: 18px;
}

.ds-card {
  background: var(--surface-2);
  border: 1px solid var(--line-soft);
  border-radius: 24px;
  box-shadow: 0 8px 24px -8px rgba(16, 24, 40, 0.12);
  transition: box-shadow 0.25s ease, border-color 0.25s ease;
}
.ds-card:hover {
  box-shadow: 0 18px 44px -30px rgba(16, 24, 40, 0.22);
  border-color: var(--line-strong);
}
.ds-card-header {
  padding: 24px 24px 0;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}
.ds-card-title {
  margin: 0;
  font-family: var(--font-display);
  font-size: var(--fs-xl);
  font-weight: 600;
  line-height: var(--lh-snug);
  color: var(--text-primary);
  letter-spacing: -0.01em;
}
.ds-card-desc {
  margin: 4px 0 0;
  font-size: var(--fs-sm);
  color: var(--text-secondary);
  line-height: var(--lh-normal);
}
.ds-card-body {
  padding: 24px;
}

.ds-field {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.ds-field-label {
  font-size: var(--fs-xs);
  font-weight: 500;
  color: var(--text-secondary);
  letter-spacing: 0.02em;
}
.ds-input {
  height: 36px;
  padding: 8px 12px;
  background: var(--surface-2);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: var(--fs-sm);
  line-height: var(--lh-normal);
  border: 1px solid var(--line-strong);
  border-radius: 12px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.ds-input::placeholder {
  color: var(--text-muted);
}
.ds-input:focus {
  border-color: var(--brand-500);
  box-shadow: 0 0 0 2px rgba(36, 87, 197, 0.2);
}
.ds-input.ds-input--error {
  border-color: #c4493d;
}
.ds-input.ds-input--error:focus {
  box-shadow: 0 0 0 2px rgba(196, 73, 61, 0.2);
}

.ds-nav-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 11px 12px;
  border-radius: 10px;
  color: inherit;
  text-decoration: none;
  font-size: var(--fs-sm);
  font-weight: 500;
  line-height: 1.35;
  cursor: pointer;
  transition: transform 0.24s cubic-bezier(0.16, 1, 0.3, 1), background-color 0.2s ease, color 0.2s ease;
}
.ds-nav-item:hover {
  background: var(--surface-hover);
}
.ds-nav-item--active {
  background: var(--surface-3);
  color: var(--brand-500);
  font-weight: 600;
}
.ds-nav-item:focus-visible {
  outline: 2px solid var(--brand-500);
  outline-offset: -2px;
}
.ds-nav-icon {
  flex-shrink: 0;
  width: 18px;
  height: 18px;
  opacity: 0.72;
}
.ds-nav-item--active .ds-nav-icon {
  opacity: 1;
}

.ds-nav-group {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.ds-nav-group + .ds-nav-group {
  padding-top: 14px;
  border-top: 1px solid var(--line-soft);
}
.ds-nav-group-label {
  padding: 0 10px;
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--text-muted);
}
.ds-nav-group-items {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.ds-chip {
  display: inline-flex;
  align-items: center;
  padding: 3px 7px;
  font-size: 11px;
  font-weight: 500;
  color: var(--text-secondary);
  background: var(--surface-3);
  border-radius: 999px;
  line-height: 1.4;
  white-space: nowrap;
}
.ds-chip--risk {
  color: #a9392f;
  background: #fef2f1;
}
.ds-chip--success {
  color: #1a6849;
  background: #effaf5;
}
.ds-chip--warning {
  color: #9a6218;
  background: #fdf9ef;
}

.ds-workspace-utility {
  position: sticky;
  top: 0;
  z-index: 12;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 20px 28px 14px;
  background: linear-gradient(180deg, rgba(248, 241, 229, 0.96), rgba(248, 241, 229, 0.82));
  backdrop-filter: blur(12px);
  border-bottom: 1px solid rgba(95, 69, 35, 0.16);
}
.ds-workspace-utility-copy {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.ds-workspace-eyebrow {
  margin: 0;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: #7e6850;
}
.ds-workspace-utility-copy strong {
  font-size: 16px;
  line-height: 1.35;
  letter-spacing: -0.02em;
  color: #2f2418;
}

.ds-theme-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  background: transparent;
  color: var(--text-secondary);
  border: 1px solid var(--line-soft);
  border-radius: 10px;
  cursor: pointer;
  transition: background-color 0.2s ease, color 0.2s ease;
}
.ds-theme-toggle:hover {
  background: var(--surface-3);
  color: var(--text-primary);
}
.ds-theme-toggle:focus-visible {
  outline: 2px solid var(--brand-500);
  outline-offset: 2px;
}
